// ─── Helpers ────────────────────────────────────────────────────────────────
function getStatus(value, min, max) {
  if (value < min) return "low";
  if (value > max) return "high";
  return "normal";
}

function getPercent(value, min, max) {
  // Map value to 0–100 within an extended range [min*0.7, max*1.3]
  const lo = min * 0.7;
  const hi = max * 1.3;
  return Math.min(100, Math.max(0, ((value - lo) / (hi - lo)) * 100));
}

const STATUS_CONFIG = {
  normal: {
    color: "#34d399",
    bg: "rgba(52,211,153,0.08)",
    label: "Normal",
    pill: "#064e3b",
  },
  low: {
    color: "#fb923c",
    bg: "rgba(251,146,60,0.08)",
    label: "Low",
    pill: "#431407",
  },
  high: {
