    label: "High",
    pill: "#500724",
  },
};

// ─── Gauge Bar ───────────────────────────────────────────────────────────────
function GaugeBar({ value, min, max, status }) {
  const pct = getPercent(value, min, max);
  const normalStart = getPercent(min, min, max);
  const normalEnd = getPercent(max, min, max);
  const color = STATUS_CONFIG[status].color;

  return (
    <div style={{ position: "relative", height: 8, borderRadius: 8, background: "rgba(255,255,255,0.07)", overflow: "visible", margin: "14px 0 6px" }}>
      {/* Normal zone */}
      <div style={{
        position: "absolute",
        left: `${normalStart}%`,
        width: `${normalEnd - normalStart}%`,
        height: "100%",
        background: "rgba(52,211,153,0.18)",
        borderRadius: 8,
      }} />
      {/* Fill up to value */}
      <div style={{
        position: "absolute",
        left: 0,
        width: `${pct}%`,
        height: "100%",
        background: `linear-gradient(90deg, ${color}88, ${color})`,
        borderRadius: 8,
        transition: "width 1s cubic-bezier(.4,0,.2,1)",
      }} />
      {/* Thumb */}
      <div style={{
        position: "absolute",
        left: `calc(${pct}% - 6px)`,
        top: -4,
        width: 14,
        height: 14,
        borderRadius: "50%",
        background: color,
        boxShadow: `0 0 8px ${color}`,
        border: "2px solid #0f1117",
        transition: "left 1s cubic-bezier(.4,0,.2,1)",
      }} />
    </div>
  );
}

// ─── Panel Card ──────────────────────────────────────────────────────────────
function PanelCard({ panel, isSelected, onClick }) {
  const status = getStatus(panel.value, panel.min, panel.max);
  const cfg = STATUS_CONFIG[status];

  return (
    <div
      onClick={onClick}
      style={{
        background: isSelected ? cfg.bg : "rgba(255,255,255,0.03)",
        border: `1.5px solid ${isSelected ? cfg.color : "rgba(255,255,255,0.07)"}`,
        borderRadius: 20,
        padding: "22px 24px",
        cursor: "pointer",
        transition: "all 0.25s ease",
        position: "relative",
        overflow: "hidden",
      }}
    >
      {/* Glow on selected */}
      {isSelected && (
        <div style={{
          position: "absolute", inset: 0, borderRadius: 20,
          boxShadow: `inset 0 0 40px ${cfg.color}18`,
          pointerEvents: "none",
        }} />
      )}

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
        <div>
          <div style={{ fontSize: 22, marginBottom: 6 }}>{panel.icon}</div>
          <div style={{ fontSize: 13, color: "rgba(255,255,255,0.45)", fontFamily: "'DM Sans', sans-serif", letterSpacing: "0.05em", textTransform: "uppercase" }}>
