          {panel.description}
        </p>
      )}
    </div>
  );
}

// ─── Radial Overview Chart ───────────────────────────────────────────────────
function RadialOverview({ panels }) {
  const data = panels.map((p) => {
    const status = getStatus(p.value, p.min, p.max);
    const pct = getPercent(p.value, p.min, p.max);
    return {
      name: p.label,
      value: Math.round(pct),
      fill: STATUS_CONFIG[status].color,
    };
  });

  return (
    <div style={{ height: 260, position: "relative" }}>
      <ResponsiveContainer width="100%" height="100%">
        <RadialBarChart
          cx="50%"
          cy="50%"
          innerRadius="30%"
          outerRadius="95%"
          data={data}
          startAngle={180}
          endAngle={-180}
        >
          <RadialBar dataKey="value" cornerRadius={6} background={{ fill: "rgba(255,255,255,0.04)" }} />
          <Tooltip
            contentStyle={{ background: "#1a1f2e", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: "#fff", fontFamily: "'DM Sans', sans-serif" }}
            formatter={(v) => [`${v}% of range`, ""]}
          />
        </RadialBarChart>
      </ResponsiveContainer>
      <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", textAlign: "center", pointerEvents: "none" }}>
        <div style={{ fontSize: 11, color: "rgba(255,255,255,0.35)", fontFamily: "'DM Sans', sans-serif", letterSpacing: "0.08em", textTransform: "uppercase" }}>Overview</div>
      </div>
    </div>
  );
}

